def get_parameters():
 global start
 global Mikrotik
 global port
 global info
 global help
 global optp
 page = str(sys.argv)
 H  = "['AllInOne.py', '-H']"
 S  = "['AllInOne.py', '-S']"
 I  = "['AllInOne.py', '-I']"
 M  = "['AllInOne.py', '-M']"
 R  = "['AllInOne.py', '-R']"
 D  = "['AllInOne.py', '-D']"
 Ms = "['AllInOne.py', '-Ms']"
 h  = "['AllInOne.py', '-h']"
 s  = "['AllInOne.py', '-s']"
 i  = "['AllInOne.py', '-i']"
 m  = "['AllInOne.py', '-m']"
 r  = "['AllInOne.py', '-r']"
 d  = "['AllInOne.py', '-d']"
 ms = "['AllInOne.py', '-ms']"

 help     = "['AllInOne.py', '--help']"
 start    = "['AllInOne.py', '--start']"
 info     = "['AllInOne.py', '--info']"
 Mikrotik = "['AllInOne.py', '--Mikrotik']"
 Reast    = "['AllInOne.py', '--Reast']"
 Ddos     = "['AllInOne.py', '--DDOS']"
 Message  = "['AllInOne.py', '--Message']"

 if help == page or H == page or h == page :
  os.system('bash $PREFIX/bin/.B24B --help ')
  os.system('bash $PREFIX/bin/.B24B ')

 elif start == page or S == page or s == page :
  os.system('bash $PREFIX/bin/.B24B --start ')

 elif info == page or I == page or i == page :
  os.system('bash $PREFIX/bin/.B24B --info ')
  os.system('bash $PREFIX/bin/.B24B ')

 elif Mikrotik == page or M == page or m == page :
  os.system('bash $PREFIX/bin/.B24B --Mikrotik ')

 elif Reast == page or R == page or r == page :
  os.system('bash $PREFIX/bin/.B24B --Reast ')

 elif Ddos == page or D == page or d == page :
  os.system('bash $PREFIX/bin/.B24B --DDOS ')

 elif Message == page or Ms == page or ms == page :
  os.system('bash $PREFIX/bin/.B24B --msg ')

 else :
  usage()
  print('are you sure this tool installed from github ?')


